#include <stdio.h>
#include <stdint.h>

const long long MOD = 1000000007LL;

long long modpow(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, K;
        char s[100005];
        scanf("%lld %lld", &N, &K);
        scanf("%s", s); // string is not needed for computation
        long long exp = (K % 2 == 1) ? N : N - 1;
        if (exp < 0) exp = 0; // when N=0, not possible per constraints
        printf("%lld\n", modpow(2, exp));
    }
    return 0;
}

